"use client";

export type {
  ChangeType,
  DiffChange,
  DiffHunk,
  DiffInput,
  DiffInputCompare,
  DiffInputParsed,
  DiffInputPatch,
  ParsedDiff,
} from "@/lib/diff";
export { computeDiff, parseDiff, resolveDiffInput } from "@/lib/diff";
export {
  DiffView,
  type DiffViewDensity,
  type DiffViewPalette,
  type DiffViewProps,
  type DiffViewVariant,
} from "./diff-view";

"use client";

import {
  type CSSProperties,
  type KeyboardEvent,
  type ReactNode,
  type Ref,
  type RefObject,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useNavigation } from "@/hooks/use-navigation";
import {
  type DiffInputCompare,
  type DiffInputParsed,
  type DiffInputPatch,
  parsedDiffIdentity,
  resolveDiffInput,
} from "@/lib/diff";
import { SplitView } from "./diff-view-split";
import { UnifiedView } from "./diff-view-unified";

export type DiffViewVariant = "hairline" | "bare" | "dense" | "viewfinder" | "statusbar";

export type DiffViewDensity = "compact" | "default" | "comfortable";
export type DiffViewPalette = "default" | "okabe-ito";

interface DiffViewBaseProps {
  mode?: "unified" | "split";
  showLineNumbers?: boolean;
  disableWordDiff?: boolean;
  label?: string;
  className?: string;
  variant?: DiffViewVariant;
  density?: DiffViewDensity;
  palette?: DiffViewPalette;
  maxHeight?: string;
  statusBar?: ReactNode;
  ref?: Ref<HTMLElement>;
}

export type DiffViewProps = (DiffInputPatch | DiffInputCompare | DiffInputParsed) &
  DiffViewBaseProps;

interface ActiveHunkState {
  parsedIdentity: string;
  value: string;
}

function resolveActiveHunk(
  activeHunkState: ActiveHunkState | null,
  parsedIdentity: string,
  hunkCount: number,
): string | null {
  if (activeHunkState?.parsedIdentity !== parsedIdentity) return null;

  const activeIndex = Number(activeHunkState.value);
  if (!Number.isInteger(activeIndex) || activeIndex < 0 || activeIndex >= hunkCount) {
    return null;
  }
  return activeHunkState.value;
}

function getFileLabel(oldPath: string | null, newPath: string | null): string | null {
  if (!oldPath && !newPath) return null;
  if (oldPath && newPath && oldPath !== newPath) return `${oldPath} → ${newPath}`;
  return oldPath ?? newPath;
}

export function DiffView(props: DiffViewProps) {
  const {
    mode = "unified",
    showLineNumbers = false,
    disableWordDiff = false,
    label,
    className,
    variant = "hairline",
    density,
    palette = "default",
    maxHeight,
    statusBar,
    ref,
  } = props;

  const patch = "patch" in props ? props.patch : undefined;
  const before = "before" in props ? props.before : undefined;
  const after = "after" in props ? props.after : undefined;
  const diff = "diff" in props ? props.diff : undefined;
  const parsed = useMemo(() => {
    if (diff != null) return resolveDiffInput({ diff });
    if (patch != null) return resolveDiffInput({ patch });
    if (before != null && after != null) return resolveDiffInput({ before, after });
    return resolveDiffInput({ patch: "" });
  }, [patch, before, after, diff]);

  const containerRef = useRef<HTMLDivElement | null>(null);
  const parsedIdentity = useMemo(() => parsedDiffIdentity(parsed), [parsed]);
  const [activeHunkState, setActiveHunkState] = useState<ActiveHunkState | null>(null);
  const activeHunk = resolveActiveHunk(activeHunkState, parsedIdentity, parsed.hunks.length);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef: containerRef as RefObject<HTMLElement | null>,
    role: "button",
    highlighted: activeHunk,
    onHighlightChange: (value) => {
      if (value !== null) setActiveHunkState({ parsedIdentity, value });
    },
    upKeys: ["k"],
    downKeys: ["j"],
    wrap: false,
    moveFocus: false,
  });

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      setActiveHunkState(null);
      return;
    }
    navKeyDown(e);
  };

  const activeIndex = activeHunk != null ? Number(activeHunk) : null;
  const activeHunkData = activeIndex != null ? parsed.hunks[activeIndex] : undefined;
  const announcement =
    activeIndex != null && activeHunkData
      ? `Hunk ${activeIndex + 1} of ${parsed.hunks.length}${activeHunkData.heading ? `: ${activeHunkData.heading}` : ""}`
      : "";

  const resolvedDensity = density ?? (variant === "dense" ? "compact" : "default");
  const fileLabel = getFileLabel(parsed.oldPath, parsed.newPath);
  const showFigCaption = variant !== "bare" && fileLabel !== null;

  const captionId = useId();
  const ariaLabel = showFigCaption ? undefined : (label ?? "Diff output");
  const ariaLabelledBy = showFigCaption ? captionId : undefined;

  const style = maxHeight ? ({ "--dv-max-h": maxHeight } as CSSProperties) : undefined;

  const isDense = variant === "dense";
  const hasHunks = parsed.hunks.length > 0;

  const body = hasHunks ? (
    mode === "split" ? (
      <SplitView
        parsed={parsed}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        isDense={isDense}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
    ) : (
      <UnifiedView
        parsed={parsed}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        isDense={isDense}
        activeHunk={activeHunk}
        onKeyDown={onKeyDown}
        containerRef={containerRef}
      />
    )
  ) : (
    // biome-ignore lint/a11y/useSemanticElements: role="status" announces the empty diff state; <output> carries form-association semantics that do not fit here.
    <div data-slot="diff-view-empty" role="status">
      No changes
    </div>
  );

  return (
    <figure
      ref={ref}
      data-slot="diff-view"
      data-variant={variant}
      data-density={resolvedDensity}
      data-diff-palette={palette}
      data-mode={mode}
      data-max-h={maxHeight ? "true" : undefined}
      aria-roledescription="diff"
      aria-label={ariaLabel}
      aria-labelledby={ariaLabelledBy}
      className={className}
      style={style}
    >
      {variant === "viewfinder" && (
        <span aria-hidden="true" data-slot="diff-view-corners">
          <span className="vf-tl" />
          <span className="vf-tr" />
          <span className="vf-bl" />
          <span className="vf-br" />
        </span>
      )}
      {showFigCaption && (
        <figcaption id={captionId} data-slot="diff-view-caption">
          {fileLabel}
        </figcaption>
      )}
      {hasHunks && maxHeight ? (
        <div data-slot="diff-view-scroll-v" className="scrollbar-thin">
          {body}
        </div>
      ) : (
        body
      )}
      {variant === "statusbar" && statusBar != null && (
        <div data-slot="diff-view-statusbar">{statusBar}</div>
      )}
      <div className="sr-only" aria-live="polite" aria-atomic="true">
        {announcement}
      </div>
    </figure>
  );
}

"use client";

import type { ChangeType, WordSegment } from "@/lib/diff";

export type DiffRowState = "added" | "removed" | "context" | "hunk" | "empty";

export const ROW_STATE: Record<ChangeType, DiffRowState> = {
  add: "added",
  remove: "removed",
  context: "context",
};

export const SR_LABEL: Partial<Record<ChangeType, string>> = {
  add: "Added: ",
  remove: "Removed: ",
};

export const LINE_PREFIX: Record<ChangeType, string> = {
  add: "+",
  // U+2212 MINUS SIGN — visually balanced with "+", and copy-paste keeps
  // a clearly minus-shaped glyph for downstream tools (delta / git compat).
  remove: "−",
  context: " ",
};

export function formatHunkHeader(hunk: {
  oldStart: number;
  oldCount: number;
  newStart: number;
  newCount: number;
  heading: string;
}): string {
  return `@@ -${hunk.oldStart},${hunk.oldCount} +${hunk.newStart},${hunk.newCount} @@${hunk.heading ? ` ${hunk.heading}` : ""}`;
}

export function LineContent({
  content,
  wordSegments,
  type,
}: {
  content: string;
  wordSegments: WordSegment[] | undefined;
  type: ChangeType;
}) {
  if (!wordSegments || (type !== "add" && type !== "remove")) {
    return <>{content}</>;
  }

  const word = type === "add" ? "added" : "removed";
  return (
    <>
      {wordSegments.map((seg, i) =>
        seg.changed ? (
          // biome-ignore lint/suspicious/noArrayIndexKey: word-diff segments render in fixed order within an immutable line and are never reordered; the segment index is the stable identity.
          <span key={i} data-word={word}>
            {seg.text}
          </span>
        ) : (
          seg.text
        ),
      )}
    </>
  );
}

"use client";

import { type KeyboardEvent, type RefObject, useMemo } from "react";
import {
  type AnnotatedChange,
  annotateWordDiff,
  createWordDiffBudget,
  type ParsedDiff,
} from "@/lib/diff";
import { formatHunkHeader, LINE_PREFIX, LineContent, ROW_STATE, SR_LABEL } from "./diff-view-line";

type UnifiedHunk = { hunk: ParsedDiff["hunks"][number]; changes: AnnotatedChange[] };

export function UnifiedView({
  parsed,
  showLineNumbers,
  disableWordDiff,
  isDense,
  activeHunk,
  onKeyDown,
  containerRef,
}: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  isDense: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLDivElement | null>;
}) {
  const hunks: UnifiedHunk[] = useMemo(() => {
    const budget = createWordDiffBudget();
    return parsed.hunks.map((hunk) => ({
      hunk,
      changes: disableWordDiff ? hunk.changes : annotateWordDiff(hunk.changes, budget),
    }));
  }, [disableWordDiff, parsed.hunks]);

  return (
    // biome-ignore lint/a11y/noStaticElementInteractions: the diff viewer is a custom keyboard-navigable composite; row navigation is handled here via onKeyDown with no native role that fits.
    // biome-ignore lint/a11y/useAriaPropsSupportedByRole: aria-label/aria-keyshortcuts describe the focusable diff navigation region; no role with a native element equivalent applies to this composite.
    <div
      ref={containerRef}
      data-slot="diff-view-rows"
      data-line-numbers={showLineNumbers ? "true" : "false"}
      aria-label="Unified diff"
      aria-keyshortcuts="j k Escape"
      // biome-ignore lint/a11y/noNoninteractiveTabindex: the container must be focusable (tabIndex=0) to receive j/k/Escape shortcuts that move between diff rows.
      tabIndex={0}
      onKeyDown={onKeyDown}
      className="scrollbar-thin"
    >
      {hunks.map(({ hunk, changes }, hi) => (
        <UnifiedHunkBlock
          // biome-ignore lint/suspicious/noArrayIndexKey: diff hunks render in fixed order for an immutable diff and are never reordered; the hunk index is the stable identity.
          key={hi}
          hunk={hunk}
          changes={changes}
          hunkIndex={hi}
          showLineNumbers={showLineNumbers}
          isDense={isDense}
          isActive={activeHunk === String(hi)}
        />
      ))}
    </div>
  );
}

function UnifiedHunkBlock({
  hunk,
  changes,
  hunkIndex,
  showLineNumbers,
  isDense,
  isActive,
}: {
  hunk: ParsedDiff["hunks"][number];
  changes: AnnotatedChange[];
  hunkIndex: number;
  showLineNumbers: boolean;
  isDense: boolean;
  isActive: boolean;
}) {
  return (
    <>
      <span
        data-row
        data-state="hunk"
        data-hunk
        data-diffgazer-navigation-item="button"
        data-value={String(hunkIndex)}
        data-active={isActive ? "true" : undefined}
      >
        {showLineNumbers && (
          <>
            <span className="diff-num" aria-hidden="true" />
            {isDense && <span className="diff-num-divider" aria-hidden="true" />}
            <span className="diff-num" aria-hidden="true" />
            {isDense && <span className="diff-num-divider" aria-hidden="true" />}
          </>
        )}
        <span className="diff-marker" aria-hidden="true" />
        <span className="diff-code">{formatHunkHeader(hunk)}</span>
      </span>
      {changes.map((change, ci) => (
        <span
          // biome-ignore lint/suspicious/noArrayIndexKey: diff change rows render in fixed order within an immutable hunk and are never reordered; the change index is the stable identity.
          key={ci}
          data-row
          data-state={ROW_STATE[change.type]}
          data-line-old={change.oldLine ?? undefined}
          data-line-new={change.newLine ?? undefined}
        >
          {showLineNumbers && (
            <>
              <span className="diff-num" aria-hidden="true">
                {change.type !== "add" ? change.oldLine : ""}
              </span>
              {isDense && <span className="diff-num-divider" aria-hidden="true" />}
              <span className="diff-num" aria-hidden="true">
                {change.type !== "remove" ? change.newLine : ""}
              </span>
              {isDense && <span className="diff-num-divider" aria-hidden="true" />}
            </>
          )}
          <span className="diff-marker" aria-hidden="true">
            {LINE_PREFIX[change.type]}
          </span>
          <span className="diff-code">
            {SR_LABEL[change.type] && <span className="sr-only">{SR_LABEL[change.type]}</span>}
            <LineContent
              content={change.content}
              wordSegments={change.wordSegments}
              type={change.type}
            />
          </span>
        </span>
      ))}
    </>
  );
}

"use client";

import { type KeyboardEvent, type RefObject, useMemo } from "react";
import { type ParsedDiff, type SplitCell, type SplitRow, toSplitRows } from "@/lib/diff";
import { formatHunkHeader, LINE_PREFIX, LineContent, ROW_STATE, SR_LABEL } from "./diff-view-line";

export function SplitView({
  parsed,
  showLineNumbers,
  disableWordDiff,
  isDense,
  activeHunk,
  onKeyDown,
  containerRef,
}: {
  parsed: ParsedDiff;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  isDense: boolean;
  activeHunk: string | null;
  onKeyDown: (e: KeyboardEvent) => void;
  containerRef: RefObject<HTMLDivElement | null>;
}) {
  const rows: SplitRow[] = useMemo(
    () => toSplitRows(parsed.hunks, !disableWordDiff),
    [disableWordDiff, parsed.hunks],
  );

  const { leftRows, rightRows } = useMemo(() => partitionSplitRows(rows), [rows]);

  return (
    // containerRef on the outer split (not on each SplitSide rows): useNavigation
    // queries by data-diffgazer-navigation-item, which only the left side registers,
    // so one shared ref covers both panes without double-counting hunks.
    // biome-ignore lint/a11y/noStaticElementInteractions: the diff viewer is a custom keyboard-navigable composite; row navigation is handled here via onKeyDown with no native role that fits.
    // biome-ignore lint/a11y/useAriaPropsSupportedByRole: aria-label/aria-keyshortcuts describe the focusable diff navigation region; no role with a native element equivalent applies to this composite.
    <div
      ref={containerRef}
      data-slot="diff-view-split"
      aria-label="Split diff"
      aria-keyshortcuts="j k Escape"
      // biome-ignore lint/a11y/noNoninteractiveTabindex: the container must be focusable (tabIndex=0) to receive j/k/Escape shortcuts that move between diff rows.
      tabIndex={0}
      onKeyDown={onKeyDown}
    >
      <SplitSide
        side="old"
        rows={leftRows}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        isDense={isDense}
        activeHunk={activeHunk}
        registerNavigationItems
      />
      <SplitSide
        side="new"
        rows={rightRows}
        showLineNumbers={showLineNumbers}
        disableWordDiff={disableWordDiff}
        isDense={isDense}
        activeHunk={activeHunk}
        registerNavigationItems={false}
      />
    </div>
  );
}

type SideEntry =
  | { kind: "separator"; hunkIndex: number; row: Extract<SplitRow, { kind: "separator" }> }
  | { kind: "cell"; cell: SplitCell };

function partitionSplitRows(rows: SplitRow[]): {
  leftRows: SideEntry[];
  rightRows: SideEntry[];
} {
  const leftRows: SideEntry[] = [];
  const rightRows: SideEntry[] = [];
  let hunkIndex = -1;

  for (const row of rows) {
    if (row.kind === "separator") {
      hunkIndex += 1;
      leftRows.push({ kind: "separator", hunkIndex, row });
      rightRows.push({ kind: "separator", hunkIndex, row });
      continue;
    }
    leftRows.push({ kind: "cell", cell: row.left });
    rightRows.push({ kind: "cell", cell: row.right });
  }

  return { leftRows, rightRows };
}

function SplitSide({
  side,
  rows,
  showLineNumbers,
  disableWordDiff,
  isDense,
  activeHunk,
  registerNavigationItems,
}: {
  side: "old" | "new";
  rows: SideEntry[];
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  isDense: boolean;
  activeHunk: string | null;
  registerNavigationItems: boolean;
}) {
  return (
    // biome-ignore lint/a11y/useSemanticElements: role="group" labels one side of the split diff; <fieldset> is for form controls and is not appropriate here.
    <div
      data-slot="diff-view-rows"
      data-side={side}
      data-line-numbers={showLineNumbers ? "true" : "false"}
      role="group"
      aria-label={side === "old" ? "Old" : "New"}
      className="scrollbar-thin"
    >
      {rows.map((entry, i) => {
        if (entry.kind === "separator") {
          const { hunkIndex, row } = entry;
          return (
            <span
              // biome-ignore lint/suspicious/noArrayIndexKey: diff rows render in fixed order for an immutable diff and are never reordered; the row index is the stable identity.
              key={i}
              data-row
              data-state="hunk"
              data-hunk
              data-diffgazer-navigation-item={registerNavigationItems ? "button" : undefined}
              data-value={registerNavigationItems ? String(hunkIndex) : undefined}
              data-active={activeHunk === String(hunkIndex) ? "true" : undefined}
            >
              {showLineNumbers && (
                <>
                  <span className="diff-num" aria-hidden="true" />
                  {isDense && <span className="diff-num-divider" aria-hidden="true" />}
                </>
              )}
              <span className="diff-marker" aria-hidden="true" />
              <span className="diff-code">{formatHunkHeader(row)}</span>
            </span>
          );
        }

        return (
          <SplitCellRow
            // biome-ignore lint/suspicious/noArrayIndexKey: diff rows render in fixed order for an immutable diff and are never reordered; the row index is the stable identity.
            key={i}
            cell={entry.cell}
            showLineNumbers={showLineNumbers}
            disableWordDiff={disableWordDiff}
            isDense={isDense}
          />
        );
      })}
    </div>
  );
}

function SplitCellRow({
  cell,
  showLineNumbers,
  disableWordDiff,
  isDense,
}: {
  cell: SplitCell;
  showLineNumbers: boolean;
  disableWordDiff: boolean;
  isDense: boolean;
}) {
  if (cell.type === "empty") {
    return (
      <span data-row data-state="empty" aria-hidden="true">
        {showLineNumbers && (
          <>
            <span className="diff-num" />
            {isDense && <span className="diff-num-divider" />}
          </>
        )}
        <span className="diff-marker" />
        <span className="diff-code">{" "}</span>
      </span>
    );
  }

  return (
    <span data-row data-state={ROW_STATE[cell.type]}>
      {showLineNumbers && (
        <>
          <span className="diff-num" aria-hidden="true">
            {cell.lineNumber ?? ""}
          </span>
          {isDense && <span className="diff-num-divider" aria-hidden="true" />}
        </>
      )}
      <span className="diff-marker" aria-hidden="true">
        {LINE_PREFIX[cell.type]}
      </span>
      <span className="diff-code">
        {SR_LABEL[cell.type] && <span className="sr-only">{SR_LABEL[cell.type]}</span>}
        <LineContent
          content={cell.content}
          wordSegments={disableWordDiff ? undefined : cell.wordSegments}
          type={cell.type}
        />
      </span>
    </span>
  );
}

/*
 * DiffView primitive styles. The component renders five variants keyed via
 * [data-slot="diff-view"][data-variant="..."] on the root <figure>. Shared
 * typography and the grid-based row layout live on the root; per-variant
 * chrome (border, corners, strip, status bar) lives in its own block. All
 * row state (added/removed/context/hunk/empty) is driven by [data-state]
 * attributes — never inline styles — so the contract is CSP-safe.
 */
@layer components {
  [data-slot="diff-view"] {
    --dv-bg: var(--background);
    --dv-fg: var(--foreground);
    --dv-border: var(--border);
    --dv-border-soft: color-mix(in oklab, var(--border) 50%, transparent);
    --dv-muted: var(--muted-foreground);

    /* Diff-only palette anchors. These are intentionally independent of the
       global --success/--destructive/--accent tokens because product themes
       may desaturate those for non-diff UI (e.g. the TUI minimal theme maps
       --success to white). A diff that lost its red/green signal would be
       unreadable, so we ship GitHub-tuned defaults here and let consumers
       swap via [data-diff-palette] or per-instance custom property override. */
    --diff-color-add: #56d364;
    --diff-color-remove: #ff7b72;
    --diff-color-hunk: #79b8ff;

    /* Derived row tints. Percent tiers: ~14% subtle row tint, ~32% strong
       word-diff overlay, ~16% hunk separator, ~18% neutral empty-pane fill. */
    --diff-added-bg: color-mix(in oklab, var(--diff-color-add) 14%, transparent);
    --diff-added-bg-strong: color-mix(in oklab, var(--diff-color-add) 32%, transparent);
    --diff-removed-bg: color-mix(in oklab, var(--diff-color-remove) 14%, transparent);
    --diff-removed-bg-strong: color-mix(in oklab, var(--diff-color-remove) 32%, transparent);
    --diff-hunk-bg: color-mix(in oklab, var(--diff-color-hunk) 16%, transparent);
    --diff-hunk-fg: color-mix(in oklab, var(--diff-color-hunk) 70%, var(--dv-fg));
    --diff-line-num-fg: color-mix(in oklab, var(--dv-muted) 90%, transparent);
    --diff-marker-fg: var(--dv-muted);
    --diff-empty-bg: color-mix(in oklab, var(--dv-muted) 18%, transparent);

    position: relative;
    display: block;
    margin: 0;
    background: var(--dv-bg);
    color: var(--dv-fg);
    overflow: hidden;
    font-family: var(--tui-font-mono, ui-monospace, SFMono-Regular, Menlo, monospace);
    font-size: 13px;
    line-height: 1.5;
    font-feature-settings:
      "calt" 0,
      "liga" 0,
      "zero" 1;
    font-variant-ligatures: none;
    font-variant-numeric: tabular-nums;
    letter-spacing: 0;
  }

  [data-slot="diff-view"][data-density="compact"] {
    font-size: 12px;
    line-height: 1.45;
  }
  [data-slot="diff-view"][data-density="comfortable"] {
    font-size: 14px;
    line-height: 1.6;
  }

  [data-slot="diff-view"][data-diff-palette="okabe-ito"] {
    --diff-color-add: #0072b2;
    --diff-color-remove: #d55e00;
    --diff-added-bg: color-mix(in oklab, var(--diff-color-add) 18%, transparent);
    --diff-added-bg-strong: color-mix(in oklab, var(--diff-color-add) 40%, transparent);
    --diff-removed-bg: color-mix(in oklab, var(--diff-color-remove) 18%, transparent);
    --diff-removed-bg-strong: color-mix(in oklab, var(--diff-color-remove) 40%, transparent);
  }

  /* File header (figcaption). */
  [data-slot="diff-view-caption"] {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 12px;
    font-size: 12px;
    color: var(--dv-fg);
    border-bottom: 1px solid color-mix(in oklab, var(--dv-border) 40%, transparent);
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  /* Rows container — grid + subgrid + horizontal scroll. Each row declares
     `min-width: max-content` so long lines extend the row past the
     container width and trigger horizontal scroll. */
  [data-slot="diff-view-rows"] {
    display: grid;
    grid-template-columns:
      [num-l] minmax(2.5ch, max-content)
      [num-r] minmax(2.5ch, max-content)
      [marker] 1.25ch
      [code] 1fr;
    overflow-x: auto;
    overflow-y: hidden;
    scrollbar-width: thin;
    scrollbar-color: var(--dv-border) var(--dv-bg);
  }

  [data-slot="diff-view-rows"][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }

  /* Split-side rows: single number column (per pane), with its own
     horizontal scroll. min-width: 0 resets default grid min-content so
     the pane truly clips at its 1fr column. */
  [data-slot="diff-view-rows"][data-side] {
    grid-template-columns:
      [num] minmax(2.5ch, max-content)
      [marker] 1.25ch
      [code] 1fr;
    min-width: 0;
  }

  [data-slot="diff-view-rows"][data-side][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }

  [data-slot="diff-view-rows"]:focus-visible {
    outline: 2px solid var(--ring, var(--dv-fg));
    outline-offset: -2px;
  }

  /* Split container — two side-by-side panes. */
  [data-slot="diff-view-split"] {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  }

  [data-slot="diff-view-split"] > [data-slot="diff-view-rows"] {
    border-right: 1px solid color-mix(in oklab, var(--dv-border) 30%, transparent);
  }
  [data-slot="diff-view-split"] > [data-slot="diff-view-rows"]:last-child {
    border-right: none;
  }

  /* Row + cells. Each row uses subgrid so cells align across rows. */
  [data-slot="diff-view-rows"] > [data-row] {
    display: grid;
    grid-template-columns: subgrid;
    grid-column: 1 / -1;
    min-width: max-content;
  }

  [data-row] > .diff-num,
  [data-row] > .diff-marker,
  [data-row] > .diff-code {
    padding-block: 1px;
  }

  [data-row][data-state="added"] {
    background: var(--diff-added-bg);
  }
  [data-row][data-state="removed"] {
    background: var(--diff-removed-bg);
  }
  [data-row][data-state="hunk"] {
    background: var(--diff-hunk-bg);
    color: var(--diff-hunk-fg);
  }
  [data-row][data-state="empty"] {
    background: var(--diff-empty-bg);
  }
  [data-row][data-active="true"] {
    box-shadow: inset 2px 0 0 0 var(--ring, var(--dv-fg));
  }

  .diff-num {
    color: var(--diff-line-num-fg);
    text-align: right;
    padding-inline: 0.5ch;
    user-select: none;
  }

  /* Marker cell — copy-paste keeps the +/− glyph (delta / git compat). */
  .diff-marker {
    color: var(--diff-marker-fg);
    text-align: center;
    user-select: text;
  }

  [data-row][data-state="added"] .diff-marker {
    color: var(--diff-color-add);
  }
  [data-row][data-state="removed"] .diff-marker {
    color: var(--diff-color-remove);
  }

  .diff-code {
    white-space: pre;
    padding-inline-end: 1ch;
    padding-inline-start: 0.5ch;
    min-width: 0;
  }

  [data-row][data-state="hunk"] .diff-code {
    color: var(--diff-hunk-fg);
  }

  /* Word-diff spans stack on top of the row tint with the strong tier. */
  [data-word="added"] {
    background: var(--diff-added-bg-strong);
    border-radius: 2px;
    padding: 0 1px;
  }
  [data-word="removed"] {
    background: var(--diff-removed-bg-strong);
    border-radius: 2px;
    padding: 0 1px;
  }

  /* Optional vertical scroll wrapper — opt-in via [data-max-h] on the root.
     Applies to both unified and split: the entire diff body gets a fixed
     max-height; horizontal scroll still works per-row-block. */
  [data-slot="diff-view"][data-max-h] [data-slot="diff-view-scroll-v"] {
    max-height: var(--dv-max-h, 240px);
    overflow-y: auto;
    scrollbar-width: thin;
    scrollbar-color: var(--dv-border) var(--dv-bg);
  }

  /* "No changes" status row. */
  [data-slot="diff-view-empty"] {
    padding: 16px;
    text-align: center;
    color: var(--dv-muted);
    font-size: 13px;
  }

  /* ============================================================
     Variant: hairline (default) — dashboard-grade safe default.
     ============================================================ */
  [data-slot="diff-view"][data-variant="hairline"] {
    border: 1px solid var(--dv-border-soft);
    border-radius: 2px;
  }

  /* ============================================================
     Variant: bare — inline docs / changelogs, no chrome.
     ============================================================ */
  [data-slot="diff-view"][data-variant="bare"] {
    background: transparent;
    border: 0;
    border-left: 2px solid color-mix(in oklab, var(--dv-border) 60%, transparent);
    border-radius: 0;
    padding-left: 12px;
    transition: border-color 120ms ease;
  }

  [data-slot="diff-view"][data-variant="bare"]:hover {
    border-left-color: var(--ring, var(--dv-fg));
  }

  /* ============================================================
     Variant: dense — Gerrit / Reviewable density.
     Compact font, visible 1px dividers between number columns.
     ============================================================ */
  [data-slot="diff-view"][data-variant="dense"] {
    border: 1px solid var(--dv-border-soft);
    border-radius: 2px;
  }

  [data-slot="diff-view"][data-variant="dense"] [data-slot="diff-view-rows"] {
    grid-template-columns:
      [num-l] minmax(3ch, max-content)
      [div-l] 1px
      [num-r] minmax(3ch, max-content)
      [div-r] 1px
      [marker] 1.25ch
      [code] 1fr;
  }
  /* Split-side rows render a single number column per pane, so dense mode
     uses a 4-cell track here (num + divider + marker + code) instead of the
     6-cell unified track above. */
  [data-slot="diff-view"][data-variant="dense"] [data-slot="diff-view-rows"][data-side] {
    grid-template-columns:
      [num] minmax(3ch, max-content)
      [div] 1px
      [marker] 1.25ch
      [code] 1fr;
  }
  [data-slot="diff-view"][data-variant="dense"]
    [data-slot="diff-view-rows"][data-line-numbers="false"] {
    grid-template-columns: [marker] 1.25ch [code] 1fr;
  }
  [data-slot="diff-view"][data-variant="dense"] .diff-num-divider {
    background: color-mix(in oklab, var(--dv-border) 40%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] [data-row][data-state="added"] .diff-num-divider {
    background: color-mix(in oklab, var(--diff-color-add) 35%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] [data-row][data-state="removed"] .diff-num-divider {
    background: color-mix(in oklab, var(--diff-color-remove) 35%, transparent);
  }
  [data-slot="diff-view"][data-variant="dense"] .diff-num {
    padding-inline: 0.75ch;
  }

  /* ============================================================
     Variant: viewfinder — four bracketed corners, family consistency
     with dialog viewfinder language.
     ============================================================ */
  [data-slot="diff-view"][data-variant="viewfinder"] {
    --vf-size: 14px;
    --vf-weight: 1.5px;
    --vf-color: var(--dv-fg);
    --vf-offset: 0px;
    position: relative;
    background: var(--dv-bg);
    padding: 14px 16px 10px;
  }

  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > span {
    position: absolute;
    pointer-events: none;
    width: var(--vf-size);
    height: var(--vf-size);
    border: 0 solid var(--vf-color);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-tl {
    top: var(--vf-offset);
    left: var(--vf-offset);
    border-top-width: var(--vf-weight);
    border-left-width: var(--vf-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-tr {
    top: var(--vf-offset);
    right: var(--vf-offset);
    border-top-width: var(--vf-weight);
    border-right-width: var(--vf-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-bl {
    bottom: var(--vf-offset);
    left: var(--vf-offset);
    border-bottom-width: var(--vf-weight);
    border-left-width: var(--vf-weight);
  }
  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-corners"] > .vf-br {
    bottom: var(--vf-offset);
    right: var(--vf-offset);
    border-bottom-width: var(--vf-weight);
    border-right-width: var(--vf-weight);
  }

  [data-slot="diff-view"][data-variant="viewfinder"] [data-slot="diff-view-caption"] {
    display: flex;
    align-items: baseline;
    gap: 8px;
    padding: 0 4px 10px;
    border-bottom: none;
    font-size: 12px;
    color: var(--dv-fg);
  }

  /* ============================================================
     Variant: statusbar — top hairline + content + optional bottom
     consumer-filled status bar slot.
     ============================================================ */
  [data-slot="diff-view"][data-variant="statusbar"] {
    background: transparent;
  }

  [data-slot="diff-view"][data-variant="statusbar"] [data-slot="diff-view-caption"] {
    border-bottom: 1px solid color-mix(in oklab, var(--dv-border) 40%, transparent);
    padding: 4px 12px;
  }

  [data-slot="diff-view"][data-variant="statusbar"] [data-slot="diff-view-statusbar"] {
    border-top: 1px solid color-mix(in oklab, var(--dv-border) 30%, transparent);
    background: color-mix(in oklab, var(--dv-fg) 6%, transparent);
    padding: 3px 12px;
    font-size: 11px;
    color: var(--dv-muted);
  }

  /* ============================================================
     A11y / motion fallbacks.
     ============================================================ */
  @media (prefers-reduced-motion: reduce) {
    [data-slot="diff-view"][data-variant="bare"] {
      transition: none;
    }
  }

  @media (forced-colors: active) {
    [data-slot="diff-view"][data-variant="hairline"],
    [data-slot="diff-view"][data-variant="dense"] {
      border-color: CanvasText;
    }
    [data-slot="diff-view"][data-variant="bare"] {
      border-left-color: CanvasText;
    }
    [data-slot="diff-view-corners"] > span {
      border-color: CanvasText;
    }
    [data-row][data-state="added"] {
      background: Canvas;
      border-inline-start: 2px solid Mark;
    }
    [data-row][data-state="removed"] {
      background: Canvas;
      border-inline-start: 2px solid LinkText;
    }
    [data-slot="diff-view-rows"]:focus-visible {
      outline-color: Highlight;
    }
  }
}
